import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  useEffect(() => {
    if (pacienteEditando) {
      setNome(pacienteEditando.nome || '');
      setTelefone(pacienteEditando.telefone || '');
    } else {
      setNome('');
      setTelefone('');
    }
  }, [pacienteEditando]);

  const handleSubmit = (e) => {
    e.preventDefault();
    const dados = { nome, telefone };
    if (pacienteEditando) {
      axios.put(`/api/pacientes/${pacienteEditando.id}`, dados)
        .then(() => {
          setMensagem('Paciente atualizado!');
          onNovoPaciente();
          onFimEdicao();
        })
        .catch(() => setMensagem('Erro ao atualizar paciente.'));
    } else {
      axios.post('/api/pacientes', dados)
        .then(() => {
          setMensagem('Paciente cadastrado!');
          onNovoPaciente();
          setNome('');
          setTelefone('');
        })
        .catch(() => setMensagem('Erro ao cadastrar paciente.'));
    }
  };

